import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as s,e as c}from"./app-be253e4c.js";const n={},o=c(`<h1 id="colrm命令" tabindex="-1"><a class="header-anchor" href="#colrm命令" aria-hidden="true">#</a> colrm命令</h1><p><code>colrm</code>命令用于编辑源代码文件，脚本文件或常规文本文件中的文本，此命令从文件中删除选定的列，列定义为一行中的单个字符。索引总是从<code>1</code>开始，而不是<code>0</code>。如果同时指定了开始和结束，则它们之间的列包括开始和结束将被删除。如果只需要删除一列，则开始和结束必须相同。<code>colrm</code>也可以从<code>stdin</code>接受输入。如果不加任何参数，则该指令不会过滤任何一行。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>colrm <span class="token punctuation">[</span>start<span class="token punctuation">]</span> <span class="token punctuation">[</span>stop<span class="token punctuation">]</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>start</code>： 指定要删除的列的起始编号。</li><li><code>stop</code>： 指定要删除的列的结束编号，省略则删除从<code>start</code>开始的所有列。</li><li><code>-V, --version</code>: 输出版本信息。</li><li><code>-h, --help</code>: 输出帮助信息。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>从标准输入中获取输入，删除<code>start</code>和<code>stop</code>之间的所有字符，包括<code>start</code>和<code>stop</code>。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>colrm <span class="token number">3</span> <span class="token number">6</span>
<span class="token comment"># 123456</span>
<span class="token comment"># 127</span>
</code></pre></div><p>从标准输入中获取输入，删除<code>start</code>之后所有的字符。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>colrm <span class="token number">3</span>
<span class="token comment"># 1234567</span>
<span class="token comment"># 12</span>
</code></pre></div><p>读<code>file.txt</code>文件中的内容，并将删除后的内容写入<code>file2.txt</code>中。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> file.txt <span class="token operator">|</span> colrm <span class="token number">3</span> <span class="token number">6</span> <span class="token operator">&gt;</span> file2.txt
</code></pre></div>`,13),t=[o];function d(l,r){return e(),s("div",null,t)}const h=a(n,[["render",d],["__file","colrm.html.vue"]]);export{h as default};
